import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is BAC?", a: "BAC means blood alcohol content. It estimates the percentage of alcohol in a person's bloodstream." },
  { q: "How is BAC calculated?", a: "BAC is commonly estimated with the Widmark formula using alcohol consumed, body weight, sex-based distribution factor, and time elapsed." },
  { q: "What BAC is considered legally drunk?", a: "In many US states, 0.08% BAC is the legal limit for most adult drivers, but impairment can begin below that level." },
  { q: "How long does it take for BAC to go down?", a: "A common estimate is about 0.015 BAC per hour, but metabolism varies by person and situation." },
  { q: "What factors affect how fast BAC rises?", a: "Body weight, sex, drink strength, drinking pace, food, medications, health, and individual metabolism can all affect BAC." },
];

const drinkTypes = [
  { label: "Beer, 12 oz at 5%", value: 1 },
  { label: "Wine, 5 oz at 12%", value: 1 },
  { label: "Spirits, 1.5 oz at 40%", value: 1 },
  { label: "Strong beer or large pour", value: 1.4 },
  { label: "Cocktail or mixed drink", value: 1.5 },
];
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function impairment(bac: number) {
  if (bac < 0.02) return "Minimal measurable effects";
  if (bac < 0.05) return "Mild relaxation and reduced attention";
  if (bac < 0.08) return "Impaired judgment and coordination";
  if (bac < 0.15) return "Legally impaired in many places";
  if (bac < 0.25) return "Severe impairment";
  return "Dangerous alcohol poisoning risk";
}
function calcBac(gender: string, weight: number, drinks: number, drinkType: number, hours: number) {
  const r = gender === "Female" ? 0.55 : 0.68;
  const alcoholGrams = drinks * drinkType * 14;
  return Math.max(0, (alcoholGrams / (weight * 453.59237 * r)) * 100 - 0.015 * hours);
}

export default function BACCalculator() {
  const [gender, setGender] = useState("Male");
  const [weight, setWeight] = useState(180);
  const [drinks, setDrinks] = useState(2);
  const [drinkType, setDrinkType] = useState(1);
  const [hours, setHours] = useState(2);
  const bac = useMemo(() => calcBac(gender, weight, drinks, drinkType, hours), [gender, weight, drinks, drinkType, hours]);
  const rows = [["0.02", "Relaxation, slight mood changes", "Attention may be reduced", "Below per se DUI limit"], ["0.05", "Lowered alertness and coordination", "Driving risk clearly increases", "Illegal limit in some countries"], ["0.08", "Impaired balance, judgment, reaction time", "High risk", "Legal limit for most US adult drivers"], ["0.10", "Clear deterioration in control", "Very high risk", "Often illegal"], ["0.15", "Major balance and speech impairment", "Extreme risk", "Illegal"], ["0.20", "Confusion, nausea, blackout risk", "Do not drive", "Medical risk"], ["0.25", "Severe impairment, injury risk", "Do not drive", "Emergency risk"], ["0.30", "Possible unconsciousness", "Do not drive", "Potentially life-threatening"]];
  return (
    <>
      <SEOHead title="Free BAC Calculator Online - Calculate Blood Alcohol Content Instantly | CalcHive" description="Free online BAC calculator. Calculate estimated blood alcohol content using the Widmark formula based on drinks, weight and time elapsed instantly. 100% free, no signup required." canonical="/bac-calculator" keywords="free BAC calculator, blood alcohol content calculator free online, drink calculator BAC free, calculate BAC free, alcohol level calculator free online" category="Health Calculators" breadcrumbName="Free BAC Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free BAC Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate blood alcohol content using the Widmark formula and see the expected impairment range.</p></div><AdPlaceholder size="banner" className="mb-8" /><div className="mb-6 rounded-2xl border border-orange-300 bg-orange-50 p-4 text-sm font-semibold text-orange-950 dark:border-orange-800 dark:bg-orange-950/35 dark:text-orange-100">Never use this calculator to determine if you are safe to drive. Blood alcohol content varies significantly between individuals. The only safe choice is not to drive after drinking any alcohol.</div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Weight (lb)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Number of drinks</label><input type="number" value={drinks} onChange={(e) => setDrinks(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Drink type</label><select value={drinkType} onChange={(e) => setDrinkType(Number(e.target.value))} className={inputClass}>{drinkTypes.map((d) => <option key={d.label} value={d.value}>{d.label}</option>)}</select></div><div className="sm:col-span-2"><label className="text-sm font-semibold block mb-2">Hours since first drink</label><input type="number" value={hours} onChange={(e) => setHours(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated BAC</p><p className="text-5xl sm:text-6xl font-black text-white">{bac.toFixed(3)}%</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Impairment level</p><p className="text-lg font-extrabold">{impairment(bac)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Estimated time to zero</p><p className="text-lg font-extrabold">{(bac / 0.015).toFixed(1)} hours</p></div></div></section><MedicalDisclaimer variant="bac" /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Blood Alcohol Content for Free</h2><p className="text-muted-foreground leading-relaxed">This drink calculator BAC estimate uses standard drinks, body weight, sex-based alcohol distribution, and time since drinking began.</p><h2 className="text-2xl font-bold">How Weight Gender and Drinks Affect Your BAC</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">BAC Level Effects on the Body</caption><thead className="bg-muted/60"><tr>{["BAC Level", "Effects on Body", "Driving Risk", "Legal Status in US"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Blood Alcohol Level Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">BAC estimates vary and cannot prove sobriety. When in doubt, arrange a safe ride and avoid driving.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/bac-calculator" headingLevel="h3" /></main>
    </>
  );
}


